// Transformar respuesta de Apollo a formato Rosecal
const people = $input.first().json.people || [];

return people.map(person => {
  const org = person.organization || {};

  return {
    json: {
      empresa: org.name || '',
      rubro: org.industry || '',
      zona: org.city ? org.city + ', ' + org.country : (org.country || 'Argentina'),
      empleados_aprox: org.employee_count ? org.employee_count.toString() : '',
      web: org.website_url || '',
      nombre_contacto: (person.first_name || '') + ' ' + (person.last_name || ''),
      cargo_contacto: person.title || '',
      email_contacto: person.email || '',
      telefono_empresa: org.phone || '',
      estado: person.email ? 'pendiente' : 'sin_email',
      email_enviado_1: '',
      email_enviado_2: '',
      email_enviado_3: '',
      fecha_ultimo_contacto: '',
      fecha_respuesta: '',
      categoria_respuesta: '',
      resumen_respuesta: '',
      accion_sugerida: '',
      urgencia: '',
      fecha_futura: '',
      notas_call: 'Importado desde Apollo.io - ' + DateTime.now().toFormat('yyyy-MM-dd'),
      call_resultado: '',
      call_detalle: '',
      proxima_accion: '',
      fecha_proximo_contacto: '',
      _apollo_id: person.id
    }
  };
}).filter(item => item.json.empresa && item.json.nombre_contacto.trim());

parameters.prompt:
=Validá si este cargo es del área de compras o abastecimiento.

Cargo: {{ $json.cargo_contacto }}
Empresa: {{ $json.empresa }}

Respondé SOLO con un JSON:
{
  "es_compras": true/false,
  "confianza": "alta/media/baja",
  "razon": "breve explicación"
}

parameters.jsCode:
// Parsear validación de IA
const aiResponse = $input.first().json.text || '{}';

try {
  const parsed = JSON.parse(aiResponse.replace(/```json\s*|\s*```/g, ''));
  const esCompras = parsed.es_compras === true;

  return [{
    json: {
      ...$input.first().json,
      estado: esCompras ? 'pendiente' : 'no_es_compras',
      notas_call: parsed.razon || ''
    }
  }];
} catch (e) {
  // Si falla, mantener como pendiente
  return [{
    json: {
      ...$input.first().json,
      estado: 'pendiente',
      notas_call: 'Error validando cargo'
    }
  }];
}

